import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"46. Jury Service","description":"","frontmatter":{"title":"46. Jury Service","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/46-jury-service.md","filePath":"ebas/mental-health/common-terms/leave/46-jury-service.md"}'),n={name:"ebas/mental-health/common-terms/leave/46-jury-service.md"};function s(i,e,c,l,h,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_46-jury-service" tabindex="-1">46. Jury Service <a class="header-anchor" href="#_46-jury-service" aria-label="Permalink to &quot;46. Jury Service&quot;">​</a></h1><p><strong>46.1</strong> An Employee required to attend for jury service during their ordinary working hours shall be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid in respect of their attendance for such jury service; and</p><p><strong>(b)</strong> the amount the Employee could reasonably expect to have received from the Employer as earnings for that period had the Employee not been performing jury service.</p><p><strong>46.2</strong> An Employee shall notify the Employer as soon as possible of the date upon which they is required to attend for jury service. Further the Employee shall give the Employer proof of their attendance at the court, the duration of such attendance and the amount received in respect of such jury service.</p><p><strong>46.3</strong> The Juries Act 2000 (Vic) contains obligations in relation to the payment of casual Employees who perform jury service. This Agreement is not intended to reduce any obligation or entitlement under those provisions.</p><p>Plain language terms: jury duty, court leave.</p>',7)])])}const d=t(n,[["render",s]]);export{m as __pageData,d as default};
